import React, { useEffect, useMemo, useState } from "react";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

function RecipesPage() {
  let [recipes, setRecipes] = useState([]);
  let [search, setSearch] = useState("chicken");
  let [selectedCategory, setSelectedCategory] = useState("");
  let [loading, setLoading] = useState(true);

  useEffect(() => {
    pobierzPrzepisy("chicken");
  }, []);

  function pobierzPrzepisy(nazwa) {
    setLoading(true);

    fetch("http://localhost:5000/api/przepisy/szukaj/" + nazwa)
      .then((response) => response.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setRecipes(data);
        } else {
          setRecipes([]);
        }
        setLoading(false);
      })
      .catch((error) => {
        console.log(error);
        setRecipes([]);
        setLoading(false);
      });
  }

  function handleSearch() {
    if (!search.trim()) {
      return;
    }

    pobierzPrzepisy(search);
  }

  let categories = useMemo(() => {
    let values = recipes
      .map((recipe) => recipe.kategoria)
      .filter((value) => value);

    return [...new Set(values)];
  }, [recipes]);

  let filteredRecipes = recipes.filter((recipe) => {
    let matchCategory =
      !selectedCategory || recipe.kategoria === selectedCategory;

    return matchCategory;
  });

  return (
    <div className="app">
      <Navbar />

      <section className="recipes-page">
        <div className="container">
          <div className="recipes-page-header">
            <h1>Przepisy</h1>
            <p>Wyszukuj przepisy z API i filtruj je według kategorii.</p>
          </div>

          <div className="recipes-layout">
            <aside className="filters-sidebar">
              <h3>Wyszukiwanie i filtry</h3>

              <div className="filter-group">
                <label>Wyszukaj nazwę przepisu</label>
                <input
                  type="text"
                  placeholder="Np. chicken, pasta, beef"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
              </div>

              <button className="search-button" onClick={handleSearch}>
                Szukaj
              </button>

              <div className="filter-group">
                <label>Kategoria</label>
                <select
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
                >
                  <option value="">Wszystkie</option>
                  {categories.map((category, index) => (
                    <option key={index} value={category}>
                      {category}
                    </option>
                  ))}
                </select>
              </div>

              <button
                className="clear-filters-button"
                onClick={() => {
                  setSelectedCategory("");
                }}
              >
                Wyczyść filtry
              </button>
            </aside>

            <div className="recipes-content">
              {loading ? (
                <p>Ładowanie przepisów...</p>
              ) : filteredRecipes.length === 0 ? (
                <p>Brak przepisów pasujących do wyszukiwania.</p>
              ) : (
                <div className="recipes-list-grid">
                  {filteredRecipes.map((recipe) => (
                    <div className="recipe-list-card" key={recipe.id}>
                      {recipe.obrazek && (
                        <img
                          src={recipe.obrazek}
                          alt={recipe.tytul}
                          className="recipe-list-image"
                        />
                      )}

                      <div className="recipe-list-card-body">
                        <h3>{recipe.tytul}</h3>

                        <div className="recipe-list-meta">
                          <span>Kategoria: {recipe.kategoria || "Brak"}</span>
                        </div>

                        <p className="recipe-list-description">
                          {recipe.instrukcje
                            ? recipe.instrukcje.substring(0, 180) + "..."
                            : "Brak opisu przepisu."}
                        </p>

                        {recipe.youtube && (
                          <a
                            href={recipe.youtube}
                            target="_blank"
                            rel="noreferrer"
                            className="youtube-link"
                          >
                            Zobacz na YouTube
                          </a>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
}

export default RecipesPage;
